/**
 * useOrbitalBridge Hook
 *
 * Decoupled bridge for trait <-> server communication via the event bus.
 * Components emit events on the bus; the bridge forwards to the server
 * and emits responses back. Replaces the tightly-coupled useServerBridge.
 *
 * Lifecycle events emitted on the bus:
 *   - `{traitName}:DISPATCH`  - before server call (event, payload, currentState)
 *   - `{traitName}:{event}:SUCCESS` - after successful server response
 *   - `{traitName}:{event}:ERROR`   - after failed server response
 *
 * @generated by Orbital Compiler (Phase 5)
 * @packageDocumentation
 */

import { useCallback } from 'react';
import { useEventBus } from '@almadar/ui/hooks';
import type { EventPayload } from '@almadar/core';
import type { EventResponse } from '@app/shared';

export type { EventRequest, EventResponse } from '@app/shared';

export interface OrbitalBridgeConfig {
  /** API base path for the trait (e.g., '/api/task-crud') */
  basePath: string;
  /** Owning orbital name — used to qualify bus keys per gap #13. */
  orbitalName: string;
  /** Trait name - used to qualify bus keys and namespace lifecycle events. */
  traitName: string;
}

export interface OrbitalBridge {
  /** Send an event to the server and emit lifecycle events on the bus */
  sendEvent: (
    event: string,
    payload?: EventPayload,
    currentState?: string
  ) => Promise<EventResponse>;
  /** The event bus instance (shared with cross-trait listeners) */
  eventBus: ReturnType<typeof useEventBus>;
}

// API base URL: empty in dev (Vite proxy handles /api), full server URL in production
const API_BASE = import.meta.env.VITE_API_URL ?? '';

export function useOrbitalBridge({ basePath, orbitalName, traitName }: OrbitalBridgeConfig): OrbitalBridge {
  const eventBus = useEventBus();

  const sendEvent = useCallback(
    async (
      event: string,
      payload?: EventPayload,
      currentState?: string
    ): Promise<EventResponse> => {
      // Emit pre-dispatch lifecycle event (for debugging, analytics, local listeners)
      eventBus.emit(`${traitName}:DISPATCH`, { event, payload, currentState });

      try {
        const response = await fetch(`${API_BASE}${basePath}/events`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          credentials: 'include',
          body: JSON.stringify({ event, payload, currentState }),
        });

        if (!response.ok) {
          const errorResponse: EventResponse = {
            success: false,
            error: `HTTP ${response.status}: ${response.statusText}`,
          };
          eventBus.emit(`${traitName}:${event}:ERROR`, { event, success: false, error: errorResponse.error });
          return errorResponse;
        }

        const result: EventResponse = await response.json();

        if (result.success) {
          eventBus.emit(`${traitName}:${event}:SUCCESS`, { event, currentState, success: true, newState: result.newState, emittedEvents: result.emittedEvents, effectResults: result.effectResults, data: result.data } as EventPayload);
          // Re-emit the transition's event on the client bus so cross-
          // trait `listens { SourceTrait EVENT → Y }` subscriptions fire.
          // Otherwise the bus only ever sees `UI:EVENT` (from Button) and
          // `${traitName}:${event}:SUCCESS` (logging) — cross-trait listeners
          // subscribe to plain `EVENT` with a source filter, so they'd never
          // fire on a user-click flow even when the server returns success.
          // Skip lifecycle events to avoid re-dispatching INIT cascades.
          if (event !== 'INIT' && event !== 'LOAD' && event !== '$MOUNT' && event !== '$UNMOUNT') {
            // Gap #13: emit qualified `UI:Orbital.Trait.Event` so cross-trait
            // `listens` subscriptions (which now subscribe to the qualified
            // key) match. `fromBridge: true` is kept on `source` for diagnostic
            // tooling that wants to distinguish bus echoes from user clicks.
            eventBus.emit(`UI:${orbitalName}.${traitName}.${event}`, payload, { orbital: orbitalName, trait: traitName, fromBridge: true, dispatched: true });
          }
          // Fix B (Phase 9.5.H): server is stateless per request. Any effect
          // with `emit: { success: "X" }` appends X to `result.emittedEvents`.
          // Fire each on the client bus; cross-trait `listens` subscribers
          // (gap #13: qualified bus keys) dispatch them back to their state
          // machines so the state cascade advances. Without this, a
          // fetch-in-INIT pattern stalls in `loading`.
          const emittedEvents = result.emittedEvents;
          if (Array.isArray(emittedEvents)) {
            for (const ev of emittedEvents) {
              const evOrbital = ev.source?.orbital ?? orbitalName;
              const evTrait = ev.source?.trait ?? traitName;
              eventBus.emit(`UI:${evOrbital}.${evTrait}.${ev.event}`, ev.payload, { ...(ev.source ?? {}), orbital: evOrbital, trait: evTrait, fromBridge: true });
            }
          }
        } else {
          eventBus.emit(`${traitName}:${event}:ERROR`, { event, currentState, success: false, error: result.error, guardFailed: result.guardFailed });
        }

        return result;
      } catch (err) {
        const errorResponse: EventResponse = {
          success: false,
          error: err instanceof Error ? err.message : 'Network error',
        };
        eventBus.emit(`${traitName}:${event}:ERROR`, { event, success: false, error: errorResponse.error });
        return errorResponse;
      }
    },
    [basePath, traitName, eventBus]
  );

  return { sendEvent, eventBus };
}

export default useOrbitalBridge;
